const item = $input.first();
const json = item.json ?? {};
const binary = item.binary ?? {};
const body = json.body ?? json;

function readBinaryJson(key) {
  const entry = binary[key];

  if (!entry?.data) {
    return null;
  }

  try {
    return JSON.parse(Buffer.from(entry.data, 'base64').toString('utf8'));
  } catch (error) {
    return {
      parseError: error.message,
      fileName: entry.fileName,
      mimeType: entry.mimeType
    };
  }
}

function getField(key) {
  return body[key] ?? json[key] ?? null;
}

const metadata = readBinaryJson('metadata') ?? {};
const manifest = readBinaryJson('manifest') ?? metadata.manifest ?? {};
const zipFile = binary.file ?? null;

const transport = {
  contractVersion: getField('contractVersion') ?? metadata.contractVersion ?? 'unknown',
  packageFormatVersion: getField('packageFormatVersion') ?? metadata.packageFormatVersion ?? manifest?.app?.packageFormatVersion ?? 'unknown',
  inspectionId: getField('inspectionId') ?? metadata.inspectionId ?? manifest?.inspection?.id ?? 'unknown',
  inspectionTitle: getField('inspectionTitle') ?? metadata.inspectionTitle ?? manifest?.inspection?.title ?? 'unknown',
  configId: getField('configId') ?? metadata.configId ?? manifest?.inspection?.configId ?? 'unknown',
  configName: getField('configName') ?? metadata.configName ?? manifest?.inspection?.configName ?? 'unknown',
  adapterId: getField('adapterId') ?? metadata.adapterId ?? 'webhook',
  fileName: getField('fileName') ?? metadata.fileName ?? zipFile?.fileName ?? 'auditm-field-package.zip',
  fileSize: Number(getField('fileSize') ?? metadata.fileSize ?? 0),
  exportedAt: getField('exportedAt') ?? metadata.exportedAt ?? manifest?.app?.exportedAt ?? new Date().toISOString()
};

const response = {
  accepted: true,
  jobId: `n8n-execution-${$execution.id}`,
  message: `AuditM-Field package accepted: ${transport.inspectionTitle}`,
  externalUrl: `https://your-n8n-host.example/execution/${$execution.id}`,
  status: 'PROCESSING'
};

return [
  {
    json: {
      transport,
      manifest,
      metadata,
      file: zipFile
        ? {
            fileName: zipFile.fileName,
            mimeType: zipFile.mimeType,
            fileSize: zipFile.fileSize
          }
        : null,
      response
    },
    binary
  }
];
